// ─── SEEDED RNG ─────────────────────────────────────────
function seededRandom(seed) {
  let s = seed;
  return () => { s = (s * 16807) % 2147483647; return (s - 1) / 2147483646; };
}

// hexPath outside component (FIX #7)
const hexPath = (cx, cy, r) => {
  let d = "";
  for (let i = 0; i < 6; i++) {
    const angle = (Math.PI / 3) * i - Math.PI / 6;
    d += (i === 0 ? "M" : "L") + `${cx + r * Math.cos(angle)},${cy + r * Math.sin(angle)}`;
  }
  return d + "Z";
};

// ─── HOOKS ──────────────────────────────────────────────
function useInView(threshold = 0.15) {
  const ref = useRef(null);
  const [isVisible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const obs = new IntersectionObserver(
      ([entry]) => { if (entry.isIntersecting) setVisible(true); },
      { threshold, rootMargin: "0px 0px -40px 0px" }
    );
    obs.observe(el);
    return () => obs.disconnect();
  }, [threshold]);
  return [ref, isVisible];
}

function useScrollProgress() {
  const [progress, setProgress] = useState(0);
  useEffect(() => {
    const handler = () => {
      const h = document.documentElement.scrollHeight - window.innerHeight;
      setProgress(h > 0 ? window.scrollY / h : 0);
    };
    window.addEventListener("scroll", handler, { passive: true });
    return () => window.removeEventListener("scroll", handler);
  }, []);
  return progress;
}

function Counter({ end, suffix = "", duration = 1800 }) {
  const [count, setCount] = useState(0);
  const [ref, vis] = useInView(0.3);
  const started = useRef(false);
  useEffect(() => {
    if (!vis || started.current) return;
    started.current = true;
    const num = parseInt(end.replace(/,/g, ""));
    const startTime = performance.now();
    const step = (now) => {
      const p = Math.min((now - startTime) / duration, 1);
      setCount(Math.floor((1 - Math.pow(1 - p, 3)) * num));
      if (p < 1) requestAnimationFrame(step);
    };
    requestAnimationFrame(step);
  }, [vis, end, duration]);
  return <span ref={ref}>{count.toLocaleString()}{suffix}</span>;
}

// ─── HERO TERMINAL (raw, no glassmorphism) ──────────────
function HeroTerminal() {
  const [lines, setLines] = useState([]);
  const allLines = useMemo(() => [
    { text: "$ init portfolio", color: "#6B6860" },
    { text: "  loading NEDN/api/v2", color: "#D4412B" },
    { text: "  MathBuddys: 222 lessons indexed", color: "#C9A96E" },
    { text: "  Spotify: PKCE handshake ✓", color: "#1DB954" },
    { text: "  Lexicon: dictionary cached", color: "#E8C547" },
    { text: "  DECA: assets compiled", color: "#3A5AE8" },
    { text: "  5 projects deployed", color: "#F0EDE6" },
  ], []);
  useEffect(() => {
    let i = 0;
    const interval = setInterval(() => {
      if (i < allLines.length) { setLines(prev => [...prev, allLines[i]]); i++; }
      else clearInterval(interval);
    }, 350);
    return () => clearInterval(interval);
  }, [allLines]);

  return (
    <div className="hero-terminal" style={{
      position: "absolute", top: "18%", right: "5%",
      fontFamily: "'IBM Plex Mono', monospace", fontSize: "0.68rem", lineHeight: 2,
      zIndex: 1, opacity: 0.55, maxWidth: "clamp(260px, 30vw, 420px)",
    }}>
      {lines.map((line, i) => (
        <div key={i} style={{
          color: line.color, opacity: 0,
          animation: "termIn 0.3s forwards", animationDelay: `${i * 0.04}s`,
          whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis",
        }}>{line.text}</div>
      ))}
      {lines.length < allLines.length && (
        <span style={{ display: "inline-block", width: 6, height: 13,
          background: "#D4412B", animation: "blink 1s step-end infinite", verticalAlign: "middle" }} />
      )}
    </div>
  );
}

