// ─── LOADER ─────────────────────────────────────────────
function Loader({ onComplete }) {
  const [phase, setPhase] = useState(0);
  useEffect(() => {
    const t1 = setTimeout(() => setPhase(1), 1600);
    const t2 = setTimeout(() => { setPhase(2); onComplete(); }, 2200);
    return () => { clearTimeout(t1); clearTimeout(t2); };
  }, [onComplete]);
  if (phase === 2) return null;
  return (
    <div style={{ position: "fixed", inset: 0, zIndex: 9999, background: "#0A0A0A",
      display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center",
      opacity: phase === 1 ? 0 : 1, transition: "opacity 0.6s cubic-bezier(0.76,0,0.24,1)",
      pointerEvents: phase === 1 ? "none" : "auto" }}>
      <div style={{ fontFamily: "'Cormorant Garamond', Georgia, serif",
        fontSize: "clamp(1.5rem, 4vw, 2.5rem)", fontWeight: 300, fontStyle: "italic",
        color: "#F0EDE6", letterSpacing: "-0.02em" }}>Joshua Sat</div>
      <div style={{ width: 60, height: 1, background: "#2A2A28", marginTop: "1.25rem",
        position: "relative", overflow: "hidden" }}>
        <div style={{ position: "absolute", top: 0, left: 0, height: "100%", width: "100%",
          background: "#D4412B", transition: "width 1.2s cubic-bezier(0.76,0,0.24,1) 0.3s" }} />
      </div>
    </div>
  );
}

