function StatItem({ number, suffix, label, index, accent }) {
  const [ref, vis] = useInView(0.2);
  return (
    <div ref={ref} style={{
      opacity: vis ? 1 : 0, transform: vis ? "translateY(0)" : "translateY(20px)",
      transition: `all 0.6s cubic-bezier(0.16,1,0.3,1) ${index * 0.08}s`,
    }}>
      <div style={{ fontFamily: "'Cormorant Garamond', Georgia, serif",
        fontSize: "clamp(1.8rem, 3vw, 2.6rem)", fontWeight: 300, fontStyle: "italic",
        color: accent || "#F0EDE6", lineHeight: 1 }}>
        <Counter end={number} suffix={suffix} />
      </div>
      <div style={{ fontFamily: "'IBM Plex Mono', monospace", fontSize: "0.5rem",
        letterSpacing: "0.12em", textTransform: "uppercase", color: "#4A4744",
        marginTop: "0.4rem" }}>{label}</div>
    </div>
  );
}

// ─── ABOUT (inverted) ───────────────────────────────────
